			JSON_PRETTY_PRINT
		);
		return $jsonEncoded === false ? '{}' : $jsonEncoded;
	}

	/**
	 * Gets a header-safe presentation of the object
	 *
	 * @return string
	 */
	public function toHeaderValue(): string {
		$jsonEncoded = json_encode(ObjectSerializer::sanitizeForSerialization($this));
		return $jsonEncoded === false ? '{}' : $jsonEncoded;
	}
}

